-- =============================================
-- EPCO - Seed: 20 tickets por cada estado (120 total)
-- Estados: abierto, asignado, en_proceso, pendiente, resuelto, cerrado
-- =============================================

USE epco;

-- Limpiar tickets y datos relacionados existentes
DELETE FROM ticket_comments;
DELETE FROM ticket_history;
DELETE FROM ticket_attachments;
DELETE FROM tickets;

-- Reiniciar auto-increment
ALTER TABLE tickets AUTO_INCREMENT = 1;
ALTER TABLE ticket_comments AUTO_INCREMENT = 1;
ALTER TABLE ticket_history AUTO_INCREMENT = 1;

