SELECT CONCAT('Tickets insertados: ', COUNT(*)) AS resultado FROM tickets;
SELECT status, COUNT(*) as cantidad FROM tickets GROUP BY status ORDER BY FIELD(status, 'abierto', 'asignado', 'en_proceso', 'pendiente', 'resuelto', 'cerrado');
