('TK-2026-0060', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'otro', 'baja', 'Limpieza profunda de equipos Finanzas', 'Limpieza interna de polvo en los 6 equipos del área de Finanzas. 4 de 6 completados.', 'en_proceso', 3, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 20 HOUR), 240, 2880, 1, DATE_SUB(NOW(), INTERVAL 2 DAY));
INSERT INTO tickets (ticket_number, user_id, user_name, user_email, user_department, category, priority, title, description, status, assigned_to, assigned_by, assigned_at, first_response_at, work_started_at, resolution, sla_response_target, sla_resolution_target, sla_response_met, created_at) VALUES
('TK-2026-0061', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'hardware', 'alta', 'Reemplazo de pantalla notebook', 'La pantalla del notebook tiene líneas verticales. Pendiente llegada del repuesto desde Santiago (3 días hábiles).', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'Pendiente repuesto - pantalla LCD 15.6" HP. Proveedor confirma despacho el viernes.', 60, 480, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0062', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'software', 'media', 'Licencia Office 365 expirada', 'La licencia de Office 365 expiró y no se puede renovar. Pendiente aprobación de presupuesto por gerencia.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'En espera de aprobación de orden de compra por Gerencia General.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 4 DAY)),
('TK-2026-0063', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'red', 'urgente', 'Enlace de fibra con proveedor caído', 'El enlace de fibra principal del ISP está caído. Proveedor informa corte por obras en carretera.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 6 HOUR), DATE_SUB(NOW(), INTERVAL 6 HOUR), DATE_SUB(NOW(), INTERVAL 5 HOUR), 'Proveedor ISP informa reparación estimada en 12 horas. Operando con enlace de respaldo.', 30, 240, 1, DATE_SUB(NOW(), INTERVAL 8 HOUR)),
('TK-2026-0064', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'acceso', 'media', 'Solicitud acceso sistema RRHH', 'Se requiere autorización de la gerencia de RRHH para otorgar acceso al módulo de remuneraciones.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'Esperando firma de autorización del Gerente de RRHH. Se envió correo recordatorio.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0065', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'hardware', 'media', 'Batería de notebook hinchada', 'La batería del notebook está hinchada y deforma el trackpad. Esperando batería de reemplazo OEM.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), 'Batería encargada a proveedor Dell. ETA: próxima semana. Equipo en uso conectado a corriente.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 5 DAY)),
('TK-2026-0066', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'software', 'alta', 'Error persistente en sistema de RRHH', 'Bug en el cálculo de vacaciones del sistema de RRHH. Se escaló al proveedor del software.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'Caso abierto con proveedor Softland - Ticket #SR-45672. Esperando parche correctivo.', 60, 480, 1, DATE_SUB(NOW(), INTERVAL 4 DAY)),
('TK-2026-0067', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'otro', 'baja', 'Compra de reguladores de voltaje', 'Se necesitan 5 reguladores de voltaje para los equipos de operaciones. Pendiente cotización.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 6 DAY), 'Se enviaron 3 cotizaciones a Adquisiciones. En proceso de comparación de precios.', 240, 2880, 1, DATE_SUB(NOW(), INTERVAL 8 DAY)),
('TK-2026-0068', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'software', 'media', 'Integración ERP con banco', 'La integración entre SAP y el portal bancario requiere certificado SSL del banco. Solicitado hace 5 días.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), 'Banco confirma emisión de certificado en 3-5 días hábiles. Caso ref: BC-2026-1199.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 6 DAY)),
('TK-2026-0069', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'hardware', 'urgente', 'Servidor de cámaras con disco lleno', 'El NVR de cámaras tiene el disco al 98%. Se necesita disco de 8TB. Pendiente compra de emergencia.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), 'OC emitida. Proveedor entrega mañana. Mientras tanto se eliminaron grabaciones antiguas no críticas.', 30, 240, 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
('TK-2026-0070', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'acceso', 'media', 'Migración a Azure AD', 'La migración de cuentas a Azure AD está pausada esperando la activación de la suscripción E3.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 6 DAY), 'Microsoft confirma activación de licencias E3 para el próximo lunes.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 8 DAY)),
('TK-2026-0071', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'red', 'alta', 'Ampliar ancho de banda enlace', 'Se requiere ampliar el enlace de internet de 100Mbps a 500Mbps. Pendiente contrato con proveedor.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 2 WEEK), DATE_SUB(NOW(), INTERVAL 2 WEEK), DATE_SUB(NOW(), INTERVAL 10 DAY), 'Propuesta comercial aprobada por Gerencia. ISP agenda instalación técnica para el 5 de marzo.', 60, 480, 1, DATE_SUB(NOW(), INTERVAL 2 WEEK)),
('TK-2026-0072', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'software', 'alta', 'Bug en cálculo de depreciación', 'El módulo de activos fijos calcula mal la depreciación acelerada. Escalado al desarrollador.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Proveedor confirmó bug. Hotfix programado para el próximo release v2026.1.3.', 60, 480, 1, DATE_SUB(NOW(), INTERVAL 5 DAY)),
('TK-2026-0073', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'hardware', 'media', 'Reemplazo masivo de teclados', 'Se aprobó el reemplazo de 20 teclados dañados por desgaste. Orden de compra emitida.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Proveedor PCFactory confirma despacho de 20 teclados Logitech K120 para el jueves.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 4 DAY)),
('TK-2026-0074', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'otro', 'baja', 'Reestructurar cableado sala servidores', 'Se necesita reestructurar el cableado del rack principal. Pendiente ventana de mantenimiento.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 5 DAY), 'Ventana de mantenimiento programada para sábado 8 de marzo, 22:00-06:00.', 240, 2880, 1, DATE_SUB(NOW(), INTERVAL 10 DAY)),
('TK-2026-0075', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'software', 'media', 'Actualizar antivirus en 50 equipos', 'La actualización del antivirus requiere reinicio. Coordinando con cada departamento para horarios.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), '30 de 50 equipos actualizados. Los 20 restantes serán durante la noche del miércoles.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 4 DAY)),
('TK-2026-0076', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'acceso', 'alta', 'Token de seguridad bancario dañado', 'El token físico del banco se dañó. Banco solicita nota formal de la empresa para reemplazo.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'Carta firmada por Gerente General enviada al banco. Esperando nuevo token en 48 horas.', 60, 480, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0077', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'red', 'media', 'Instalar punto de red en nueva oficina', 'Se necesita cableado estructurado para 4 nuevos puestos de trabajo. Pendiente compra de materiales.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), 'Materiales (cable UTP Cat6, jacks, canaletas) llegarán el viernes.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 6 DAY)),
('TK-2026-0078', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'hardware', 'media', 'Impresora necesita mantenimiento preventivo', 'La impresora Xerox requiere cambio de drum y fusor. Repuestos en camino desde Santiago.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Drum y fusor Xerox despachados via Chilexpress. Tracking: 99912345678.', 120, 1440, 1, DATE_SUB(NOW(), INTERVAL 5 DAY)),
('TK-2026-0079', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'software', 'urgente', 'Parche de seguridad crítico Windows', 'Vulnerabilidad CVE-2026-0012 requiere parche urgente en servidores. Esperando ventana de mantenimiento.', 'pendiente', 2, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), 'Parche descargado y testeado en entorno QA. Despliegue programado esta noche a las 23:00.', 30, 240, 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
('TK-2026-0080', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'otro', 'baja', 'Cotización de laptops nuevos 2026', 'Se requieren 10 laptops nuevos para el plan de renovación 2026. Pendiente aprobación de presupuesto.', 'pendiente', 3, 1, DATE_SUB(NOW(), INTERVAL 2 WEEK), DATE_SUB(NOW(), INTERVAL 2 WEEK), DATE_SUB(NOW(), INTERVAL 12 DAY), '3 cotizaciones entregadas a Gerencia. Presupuesto en evaluación para aprobación en comité del viernes.', 240, 2880, 1, DATE_SUB(NOW(), INTERVAL 15 DAY));
INSERT INTO tickets (ticket_number, user_id, user_name, user_email, user_department, category, priority, title, description, status, assigned_to, assigned_by, assigned_at, first_response_at, work_started_at, resolved_at, resolution, resolution_type, sla_response_target, sla_resolution_target, sla_response_met, sla_resolution_met, created_at) VALUES
('TK-2026-0081', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'software', 'media', 'Outlook no envía correos', 'Outlook muestra error "Cannot connect to server" al intentar enviar correos electrónicos.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 23 HOUR), DATE_SUB(NOW(), INTERVAL 20 HOUR), 'Se reconfiguró el perfil de Outlook y se actualizó la configuración SMTP. Correos funcionando correctamente.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
('TK-2026-0082', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'hardware', 'alta', 'Monitor parpadea intermitentemente', 'El monitor Dell de mi estación parpadea cada 2-3 segundos. Imposible trabajar así.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), 'Se reemplazó el cable DisplayPort dañado por uno nuevo. Monitor funcionando sin parpadeo.', 'solucionado', 60, 480, 1, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0083', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'red', 'urgente', 'Corte total de red en bodega', 'Toda la bodega principal quedó sin red. Afecta lectores de código y sistema de inventario.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Puerto del switch principal estaba configurado como trunk en vez de access. Reconfigurado y verificado.', 'solucionado', 30, 240, 1, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0084', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'acceso', 'media', 'No puedo acceder al portal tributario', 'Al ingresar al portal del SII, aparece error de certificado SSL. No permite continuar.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Se instaló el certificado raíz del SII en el navegador. Acceso restaurado exitosamente.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 5 DAY)),
('TK-2026-0085', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'software', 'baja', 'Instalar 7-Zip en equipo', 'Necesito el programa 7-Zip para descomprimir archivos .7z que me envían los proveedores.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), 'Se instaló 7-Zip versión 24.09 (64-bit). Archivos .7z se abren correctamente.', 'solucionado', 240, 2880, 1, 1, DATE_SUB(NOW(), INTERVAL 6 DAY)),
('TK-2026-0086', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'red', 'media', 'WiFi no aparece en laptop', 'Mi laptop no detecta ninguna red WiFi. El icono de WiFi tiene una X roja.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 18 HOUR), 'El adaptador WiFi estaba deshabilitado. Se habilitó desde Administrador de Dispositivos y se actualizó el driver.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
('TK-2026-0087', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'hardware', 'alta', 'Fuente de poder quemada', 'El PC de la estación de monitoreo no enciende. Se escuchó un pop y salió olor a quemado.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'Se reemplazó fuente de poder quemada por Corsair 650W nueva. Equipo funcionando sin problemas.', 'solucionado', 60, 480, 1, 1, DATE_SUB(NOW(), INTERVAL 4 DAY)),
('TK-2026-0088', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'acceso', 'alta', 'Desbloquear cuenta Active Directory', 'Mi cuenta de red se bloqueó y no puedo iniciar sesión en Windows.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'Cuenta desbloqueada en Active Directory y contraseña temporal asignada. Usuario cambió contraseña exitosamente.', 'solucionado', 60, 480, 1, 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
('TK-2026-0089', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'software', 'media', 'Error Java en aplicación portuaria', 'La aplicación PortControl muestra "Java Runtime Error" al iniciar. No se puede registrar movimiento de carga.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), 'Se desinstaló Java 8 corrupto e instaló Java 17 LTS. Aplicación PortControl funciona correctamente.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 6 DAY)),
('TK-2026-0090', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'otro', 'baja', 'Etiquetar cables de red en oficina', 'Los cables de red del rack de Administración no están etiquetados. Dificulta el troubleshooting.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 1 WEEK), DATE_SUB(NOW(), INTERVAL 6 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Se etiquetaron los 24 cables de red con etiquetas impresas (puerto, ubicación, usuario).', 'solucionado', 240, 2880, 1, 1, DATE_SUB(NOW(), INTERVAL 8 DAY)),
('TK-2026-0091', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'hardware', 'urgente', 'Lector de código de barras dañado', 'El lector de código de barras de la estación de recepción no lee correctamente.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 22 HOUR), 'Se limpió la ventana del láser y se reconfiguró el baudrate. Lector funcionando al 100%.', 'solucionado', 30, 240, 1, 1, DATE_SUB(NOW(), INTERVAL 1 DAY)),
('TK-2026-0092', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'software', 'media', 'Excel muestra texto en vez de números', 'Las celdas de Excel muestran fórmulas como texto en vez de calcular el resultado.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Las celdas estaban formateadas como Texto. Se cambió formato a Número y se recalculó la hoja.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 4 DAY)),
('TK-2026-0093', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'red', 'alta', 'Punto de acceso WiFi no responde', 'El AP Ubiquiti del muelle 1 dejó de funcionar. Sin WiFi en toda esa zona.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), 'El AP tenía firmware corrupto. Se restauró de fábrica y se reconfiguró con perfil estándar.', 'solucionado', 60, 480, 1, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0094', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'acceso', 'media', 'Crear cuenta para nuevo colaborador', 'Se necesita cuenta de correo, AD y acceso a sistemas para nuevo colaborador Juan Tapia.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Cuenta creada: juan.tapia@puertocoquimbo.cl - AD, Office 365, VPN y acceso a carpeta de Administración configurados.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 5 DAY)),
('TK-2026-0095', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'software', 'alta', 'Windows Update falla con error 0x800', 'Windows Update muestra error 0x80070002 y no puede instalar actualizaciones de seguridad.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 6 DAY), DATE_SUB(NOW(), INTERVAL 6 DAY), DATE_SUB(NOW(), INTERVAL 6 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), 'Se ejecutó DISM /RestoreHealth y SFC /scannow. Componentes reparados, actualizaciones instaladas.', 'solucionado', 60, 480, 1, 1, DATE_SUB(NOW(), INTERVAL 7 DAY)),
('TK-2026-0096', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'hardware', 'media', 'Parlantes del PC no funcionan', 'Los parlantes integrados del monitor no reproducen sonido. Audio funciona con audífonos.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY), 'El dispositivo de audio por defecto estaba configurado en HDMI. Se cambió a los parlantes del monitor.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0097', 6, 'Usuario Demo', 'usuario@puertocoquimbo.cl', 'Operaciones', 'otro', 'media', 'Limpieza de virus en USB', 'Una USB del área contiene un virus detectado por Kaspersky. No se puede acceder a los archivos.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 20 HOUR), 'Se eliminó malware tipo ransomware. Archivos recuperados del último backup. USB formateada.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
('TK-2026-0098', 7, 'María González', 'maria.gonzalez@puertocoquimbo.cl', 'Administración', 'software', 'urgente', 'Sistema de asistencia caído', 'El sistema de control de asistencia (reloj biométrico) no registra marcaciones desde las 7:00 AM.', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY), 'El servicio del software ZKAccess estaba detenido. Se reinició y se sincronizaron las marcaciones pendientes.', 'solucionado', 30, 240, 1, 1, DATE_SUB(NOW(), INTERVAL 5 DAY)),
('TK-2026-0099', 8, 'Carlos Pérez', 'carlos.perez@puertocoquimbo.cl', 'Operaciones', 'hardware', 'media', 'Cambiar tóner de impresora', 'La impresora HP LaserJet indica "tóner bajo". Las impresiones salen muy claras.', 'resuelto', 2, 1, DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'Se reemplazó tóner HP 26A por uno nuevo. Calidad de impresión restaurada.', 'solucionado', 120, 1440, 1, 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
('TK-2026-0100', 9, 'Ana López', 'ana.lopez@puertocoquimbo.cl', 'Finanzas', 'red', 'alta', 'Carpeta compartida inaccesible', 'No puedo acceder a \\\\servidor\\finanzas desde mi equipo. Error: "No se puede acceder a la red".', 'resuelto', 3, 1, DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), 'El protocolo SMBv1 estaba deshabilitado. Se habilitó SMBv3 y se mapeó la unidad correctamente.', 'solucionado', 60, 480, 1, 1, DATE_SUB(NOW(), INTERVAL 5 DAY));
